import { useEffect, useState } from "react";
import { useParams } from "react-router-dom";
import { getProduct, addToCart, addRating } from "../api/api";

function ProductDetail() {
  const { id } = useParams();

  const [product, setProduct] = useState(null);
  const [rating, setRating] = useState(5);
  const [amount, setAmount] = useState(1);

  useEffect(() => {
    loadProduct();
  }, [id]);

  async function loadProduct() {
    try {
      const data = await getProduct(id);
      setProduct(data);
    } catch (error) {
      console.error("Fel vid hämtning av produkt:", error);
    }
  }

  async function handleAddToCart() {
    try {
      await addToCart(1, id, amount);
      alert("Produkten lades i varukorgen");
    } catch (error) {
      console.error("Fel vid lägg till i varukorg:", error);
      alert("Det gick inte att lägga till produkten i varukorgen");
    }
  }

  async function handleRating() {
    try {
      await addRating(id, rating);
      await loadProduct();
      alert("Rating skickad");
    } catch (error) {
      console.error("Fel vid rating:", error);
      alert("Det gick inte att skicka rating");
    }
  }

  if (!product) return <p>Laddar...</p>;

  return (
    <div style={{ padding: "30px" }}>
      <h2>{product.product.name}</h2>

      <p>{product.product.price} kr</p>

      <p>{product.product.description}</p>

      {product.product.imageUrl && (
        <img
          src={product.product.imageUrl}
          alt={product.product.name}
          style={{
            width: "250px",
            marginTop: "10px",
            marginBottom: "20px",
            display: "block"
          }}
        />
      )}

      <div style={{ marginBottom: "20px" }}>
        <label htmlFor="amount">Antal: </label>
        <select
          id="amount"
          value={amount}
          onChange={(e) => setAmount(Number(e.target.value))}
        >
          <option value="1">1</option>
          <option value="2">2</option>
          <option value="3">3</option>
          <option value="4">4</option>
          <option value="5">5</option>
        </select>
      </div>

      <button onClick={handleAddToCart}>
        Lägg i varukorg
      </button>

      <h3 style={{ marginTop: "30px" }}>Rating</h3>

      <p>Snitt: {Number(product.averageRating || 0).toFixed(1)}</p>

      <h4>Alla betyg</h4>
      {product.ratings && product.ratings.length > 0 ? (
        <ul>
          {product.ratings.map((r, index) => (
            <li key={index}>
              {r.value}
            </li>
          ))}
        </ul>
      ) : (
        <p>Inga betyg än.</p>
      )}

      <div style={{ marginTop: "20px" }}>
        <select
          value={rating}
          onChange={(e) => setRating(Number(e.target.value))}
        >
          <option value="1">1</option>
          <option value="2">2</option>
          <option value="3">3</option>
          <option value="4">4</option>
          <option value="5">5</option>
        </select>

        <button
          onClick={handleRating}
          style={{ marginLeft: "10px" }}
        >
          Skicka rating
        </button>
      </div>
    </div>
  );
}

export default ProductDetail;
